        dp[i][i] = freq[i]
        opt[i][i] = i
    }

    for (len in 2..n) {
        for (i in 0..n - len) {
            val j = i + len - 1
            dp[i][j] = Int.MAX_VALUE
            val costSum = prefix[j + 1] - prefix[i]
            val lo = opt[i][j - 1]
            val hi = if (i + 1 <= j) opt[i + 1][j] else j
            for (k in lo..hi) {
                val left = if (k > i) dp[i][k - 1] else 0
                val right = if (k < j) dp[k + 1][j] else 0
                val v = left + right + costSum
                if (v < dp[i][j]) {
                    dp[i][j] = v
                    opt[i][j] = k
